"""Async `AsyncRun` handle. Async mirror of `_run.Run`.

Like `_run.py`, this module only references `AsyncClient` through
`self.client`, so the dependency runs one way: `_async_run` imports
`_run_base` (and types); it does not import `_async_client`. The
inverse direction (constructing `AsyncRun` from `AsyncClient` /
`AsyncAgent.send`) is kept lazy so there is no module-load cycle.
"""

from __future__ import annotations

import inspect
import json
from collections.abc import AsyncIterator
from typing import TYPE_CHECKING, Any, Mapping

from ._run_base import _RunBase, _TERMINAL_RUN_STATUSES
from .errors import UnsupportedRunOperationError
from .types import (
    ConversationTurn,
    JsonObject,
    RunResult,
    RunSnapshot,
    RunStreamEvent,
    SendOptions,
)

if TYPE_CHECKING:
    from ._async_client import AsyncClient


class AsyncRun(_RunBase):
    """Async mirror of `Run`. Streams expose `__aiter__`.

    Inherits state, identity tracking, listener registry, and pure
    state-mutation logic from `_RunBase`. `__init__` only accepts
    snapshot-based construction (no `event_stream`) because `__init__`
    cannot `await`. To wrap a server-side Send stream, use the
    `_from_stream` classmethod, which constructs the run, pulls the
    first envelope to populate `run_id` / `agent_id` / any terminal
    result, and returns a fully-initialized object. This keeps
    `AsyncRun(...)` from ever returning a half-built run that would
    only work if the caller remembered to `await run._prime_stream()`.
    """

    client: "AsyncClient"

    def __init__(
        self,
        *,
        client: "AsyncClient",
        run_id: str = "",
        agent_id: str = "",
        snapshot: RunSnapshot | None = None,
        send_options: SendOptions | None = None,
    ) -> None:
        super().__init__(
            client=client,
            run_id=run_id,
            agent_id=agent_id,
            snapshot=snapshot,
            send_options=send_options,
        )
        # Set by `_from_stream` when the run wraps a server-side stream;
        # otherwise the run is snapshot-only.
        self._event_stream: AsyncIterator[JsonObject] | None = None

    @classmethod
    async def _from_stream(
        cls,
        *,
        client: "AsyncClient",
        agent_id: str,
        event_stream: AsyncIterator[JsonObject],
        send_options: SendOptions | None,
        api_key: str,
    ) -> "AsyncRun":
        """Build a fully-primed `AsyncRun` that wraps a server-side stream.

        Async `__init__` can't `await`, so wiring up a stream-backed
        run requires an awaited step. Doing that step here (instead
        of asking callers to remember a post-construction
        `await run._prime_stream()`) makes the contract explicit: the
        only way to hand an `AsyncRun` an event stream is through this
        method, and the returned run is always primed.
        """
        run = cls(client=client, agent_id=agent_id, send_options=send_options)
        run._event_stream = event_stream
        run._api_key = api_key
        # Pull and buffer the first envelope so `run.id` /
        # `run.agent_id` are populated and any terminal-result envelope
        # is cached before the user starts iterating.
        try:
            raw = await event_stream.__anext__()
        except StopAsyncIteration:
            run._event_stream = None
            return run
        event = RunStreamEvent.from_json(raw)
        await run._handle_event(event)
        run._buffer.append(event)
        return run

    def __aiter__(self) -> AsyncIterator[RunStreamEvent]:
        return self._events()

    def events(self) -> AsyncIterator[RunStreamEvent]:
        return self._events()

    async def stream(self) -> AsyncIterator[Any]:
        async for event in self._events():
            if event.sdk_message is not None:
                yield event.sdk_message

    def messages(self) -> AsyncIterator[Any]:
        return self.stream()

    async def iter_text(self) -> AsyncIterator[str]:
        async for message in self.stream():
            if getattr(message, "type", "") != "assistant":
                continue
            content = getattr(getattr(message, "message", None), "content", ())
            for block in content:
                text = getattr(block, "text", "")
                if text:
                    yield text

    async def text(self) -> str:
        if self.result:
            return self.result
        if self._terminal_result is None:
            await self.wait()
        return self.result

    async def wait(self) -> RunResult:
        if self._event_stream is not None or self._buffer:
            async for _ in self._events():
                pass
            if self._terminal_result is not None:
                return self._result_with_accumulated_usage(self._terminal_result)
        if self._terminal_result is not None:
            return self._result_with_accumulated_usage(self._terminal_result)
        result = await self.client.wait_live_run(self.id)
        # `_apply_result` returns status-listener thunks; await any
        # awaitables they return so async listeners registered via
        # `on_did_change_status` actually run to completion.
        for callback in self._apply_result(result):
            await _maybe_await(callback())
        self._terminal_result = result
        return self._result_with_accumulated_usage(result)

    def observe(
        self, *, after_offset: str | None = None
    ) -> AsyncIterator[RunStreamEvent]:
        # `client.observe_run` is an async generator function, so calling it
        # returns the generator without `await`. Callers iterate it directly:
        # `async for event in run.observe(): ...`.
        return self.client.observe_run(self.id, after_offset=after_offset)

    async def cancel(self) -> None:
        if self.status in _TERMINAL_RUN_STATUSES:
            raise UnsupportedRunOperationError(
                "cancel",
                f"Run {self.id!r} is already in terminal status {self.status!r}; "
                "cancel is not applicable.",
            )
        await self.client.cancel_run(self.id, agent_id=self.agent_id)

    async def conversation_json(self) -> str:
        response = await self.client._agent_unary(
            "GetRunConversation", {"runId": self.id}
        )
        return str(response.get("conversationJson", ""))

    async def conversation(self) -> list[ConversationTurn]:
        raw = await self.conversation_json()
        if not raw:
            return []
        loaded = json.loads(raw)
        if not isinstance(loaded, list):
            return []
        return [
            ConversationTurn.from_json(item)
            for item in loaded
            if isinstance(item, Mapping)
        ]

    async def _events(self) -> AsyncIterator[RunStreamEvent]:
        while self._buffer:
            yield self._buffer.pop(0)
        while self._event_stream is not None:
            try:
                raw = await self._event_stream.__anext__()
            except StopAsyncIteration:
                self._event_stream = None
                return
            event = RunStreamEvent.from_json(raw)
            await self._handle_event(event)
            yield event

    async def _handle_event(self, event: RunStreamEvent) -> None:
        # State-only side-effects happen inside `_apply_event_state`
        # (shared with sync `Run`). Async-specific work: await each
        # thunk's return value if it produced an awaitable. Status
        # listeners registered via `on_did_change_status` are wrapped
        # in thunks too, so async listeners are awaited the same way
        # `on_delta` / `on_step` callbacks are.
        for callback in self._apply_event_state(event):
            await _maybe_await(callback())


async def _maybe_await(value: Any) -> None:
    if inspect.isawaitable(value):
        await value
